  ('karzinogen-kristallin', 'Kristalline Karzinogene (Inhalation)', 'Crystalline Carcinogens', 'Kristallines Siliziumdioxid (Quarz) - IARC Gruppe 1 Karzinogen bei Inhalation. NICHT verwechseln mit amorphem SiO₂ (E 551)!'),
  ('nano-bewertet', 'Nano-bewertete Zusatzstoffe', 'Nano-evaluated Additives', 'Lebensmittelzusatzstoffe mit Nano-Bewertung durch EFSA - wie E 551 (2018/2024: keine Sicherheitsbedenken für Aggregate)'),
  ('niedrige-bioverfuegbarkeit', 'Niedrige Bioverfügbarkeit Si-Formen', 'Low Bioavailability Si Forms', 'Kieselsäure-Gel (<5%), Siliziumdioxid (<4%), kolloidale Kieselsäure (~1%), Schachtelhalm (~1%) - trotz Zulassung/Verkauf praktisch nicht bioverfügbar!'),
  ('hohe-bioverfuegbarkeit', 'Hohe Bioverfügbarkeit Si-Formen', 'High Bioavailability Si Forms', 'MMST (~64%), freie OSA (~43%), ch-OSA (~17%) - die einzig sinnvollen Formen für Si-Supplementierung'),
  ('botanicals', 'Pflanzliche Extrakte (Botanicals)', 'Botanical Extracts', 'Nicht-harmonisierte Kategorie in der EU - nationale Regelungen; Schachtelhalm als THMP zugelassen'),
  ('thmp', 'Traditional Herbal Medicinal Products', 'THMP', 'Traditionelle pflanzliche Arzneimittel nach RL 2004/24/EG - Schachtelhalm hat EMA/HMPC-Monographie für Durchspülung'),
  ('thiaminase-risiko', 'Thiaminase-haltige Pflanzen', 'Thiaminase-containing Plants', 'Pflanzen die Thiaminase enthalten und bei Langzeitanwendung B1-Mangel verursachen können - Schachtelhalm, Adlerfarn'),
  ('kontaminationsrisiko', 'Kontaminationsrisiko Botanicals', 'Botanical Contamination Risk', 'Pflanzenextrakte mit Risiko für Verwechslung/Verfälschung mit toxischen Arten - Schachtelhalm (E. arvense vs. E. palustre)'),
  ('zugelassen-chosa', 'ch-OSA (zugelassen Anhang II)', 'ch-OSA (Approved Annex II)', '✅ Cholin-stabilisierte Orthokieselsäure - zugelassen seit VO (EG) 1170/2009; EFSA-bewertet 2009; klinische Studien vorhanden'),
  ('nicht-zugelassen-bambus', 'Bambusextrakt (nicht als Si-Quelle)', 'Bamboo Extract (not as Si source)', '⚠️ Bambusextrakt ist NICHT in Anhang II als Siliziumquelle gelistet - nur als Botanical verkaufbar'),
  ('klinische-studien-vorhanden', 'Klinische Studien vorhanden', 'Clinical Studies Available', '✅ ch-OSA: Barel 2005 (Haut/Haare/Nägel), Spector 2008 (Knochen). MMST: diverse. Bambus: KEINE!'),
  ('keine-humanstudien', 'Keine Humanstudien', 'No Human Studies', '⚠️ Substanzen ohne kontrollierte Humanstudien - Bambusextrakt, viele Botanicals'),
  ('phytolith-silizium', 'Phytolith-Silizium (pflanzlich)', 'Phytolith Silicon (plant-based)', '⚠️ Silizium in Pflanzen (Bambus, Schachtelhalm) liegt als biogene Kieselsäure in Phytolithen vor - hochpolymerisiert, kaum bioverfügbar'),
  ('kalium-verbindungen', 'Kalium-Verbindungen', 'Potassium Compounds', '✅ Alle in Anhang II RL 2002/46/EG zugelassenen Kaliumquellen für NEM'),
  ('mengenelemente', 'Mengenelemente', 'Macrominerals', 'Mineralstoffe mit Tagesbedarf >100 mg (Kalium, Calcium, Magnesium, Natrium, Phosphor)'),
  ('elektrolyte', 'Elektrolyte', 'Electrolytes', 'Geladene Ionen für Nerven-, Muskel- und Herzfunktion (K⁺, Na⁺, Ca²⁺, Mg²⁺, Cl⁻)'),
  ('hyperkaliämie-risiko', '⚠️ Hyperkaliämie-Risiko', 'Hyperkalemia Risk', '⚠️ SICHERHEITSKRITISCH: Substanzen mit Risiko für lebensbedrohliche Hyperkaliämie bei Risikogruppen'),
  ('nierenstein-prophylaxe', 'Nierensteinprophylaxe', 'Kidney Stone Prevention', 'Substanzen zur Prävention von Nierensteinen (Calciumoxalat, Harnsäure, Cystin)'),
  ('alkalisierend', 'Alkalisierende Verbindungen', 'Alkalizing Compounds', 'Substanzen die den Urin-pH erhöhen (Citrate, Bicarbonate)'),
  ('gi-ulkus-risiko', '⚠️ GI-Ulkus-Risiko', 'GI Ulcer Risk', '⚠️ Substanzen mit Risiko für gastrointestinale Erosionen/Ulzera (feste KCl-Formen)'),
  ('raas-interaktion', '⚠️ RAAS-Interaktion', 'RAAS Interaction', '⚠️ Substanzen mit gefährlicher Interaktion mit ACE-Hemmern, ARBs, K-sparenden Diuretika'),
  ('kalium-verbindungen-zugelassen', 'Kalium-Verbindungen (EU-zugelassen)', 'Potassium Compounds (EU-approved)', '✅ In Anhang II RL 2002/46/EG zugelassene K-Quellen: KCl, K-Citrat, K-Gluconat, K-Bicarbonat, K-Carbonat, K-Lactat, K-Malat, K-Sulfat, K-Glycerophosphat, K-L-Pidolat, K-Hydroxid, K-Orthophosphate'),
  ('kalium-verbindungen-nicht-zugelassen', '❌ Kalium-Verbindungen (NICHT zugelassen)', 'Potassium Compounds (NOT approved)', '❌ NICHT in Anhang II: Kaliumaspartat (trotz EFSA Opinion 883/2008)'),
  ('grosse-tabletten', '⚠️ Große Tabletten erforderlich', 'Large tablets required', '⚠️ K-Gluconat hat niedrigsten K-Gehalt (16,69%) = größte Tabletten für gleiche K-Dosis'),
  ('kalium-alkalisierend', 'Kalium-Formen (alkalisierend)', 'Potassium Forms (alkalizing)', '✅ K-Bicarbonat, K-Citrat, K2HPO4 (schwach), K3PO4 (stark) - erhöhen Urin-pH'),
  ('kalium-neutral', 'Kalium-Formen (neutral)', 'Potassium Forms (neutral)', 'KCl, K-Gluconat - keine Säure-Base-Wirkung'),
  ('kalium-sauer', 'Kalium-Formen (säuernd)', 'Potassium Forms (acidifying)', 'KH2PO4 - sauer (pH ~4,5)'),
  ('phosphat-risiko', '⚠️ Phosphat-Risiko', 'Phosphate Risk', '⚠️ EFSA 2019: ADI 40 mg P/kg/Tag. ADI-Überschreitung bei Kindern! CKD = vulnerable Population!'),
  ('doppelrisiko-ckd', '⚠️ Doppelrisiko bei CKD (K+P)', 'Double Risk CKD (K+P)', '⚠️ K-Phosphate bei CKD: DOPPELTE Akkumulation von Kalium UND Phosphat!'),
  ('brausetabletten', '✅ Brausetabletten-geeignet', 'Effervescent-suitable', '✅ K-Bicarbonat: Standard für Brausetabletten (+ Citronensäure → K-Citrat + CO2)'),
  ('stark-basisch', '⚠️ Stark basisch (ätzend)', 'Strongly basic (caustic)', '⚠️ K3PO4: pH 11,8 = stark basisch = potentiell ätzend! Für NEM nicht empfohlen!'),
  ('keine-supplementierung', '⚠️ KEINE Supplementierung empfohlen', 'NO Supplementation Recommended', '⚠️ Natriumchlorid: BfR empfiehlt KEINE Supplementierung. EU-Bevölkerung bereits überversorgt (150-250% AI).'),
  ('sport-elektrolyte', '✅ Sport-Elektrolyte', 'Sports Electrolytes', '✅ NaCl in Sport-Elektrolytgetränken: 460-1150 mg Na/L bei >2h Ausdauerbelastung.'),
  ('medizinische-indikation', '⚠️ Nur medizinische Indikation', 'Medical Indication Only', '⚠️ NaCl bei POTS/orthostatischer Hypotonie: Nur unter ärztlicher Aufsicht!'),
  ('orotat-warnung', '❌ Orotat-Salze', 'Orotate Salts', '❌ ALLE Orotat-Salze (K, Mg, Zn, Li): EFSA Sicherheitsbedenken. NICHT in EU zugelassen!'),
  ('lithium-interaktion', '⚠️ Lithium-Interaktion', 'Lithium Interaction', '⚠️ NaCl und Lithium: Kritische Wechselwirkung! Stabile Na-Zufuhr erforderlich.'),
  ('enterokokken-probiotika', 'Enterokokken-Probiotika', 'Enterococcal Probiotics', 'ACHTUNG: EFSA QPS AUSGESCHLOSSEN! Stammspezifische Sicherheitsbewertung erforderlich. E. faecium sicherer als E. faecalis.'),
  ('enterokokken-forschung', 'Enterokokken (Forschung)', 'Enterococci (Research)', 'Enterokokken-Arten ohne kommerzielle Probiotika-Produkte. E. durans und E. hirae: wissenschaftlich interessant, aber NICHT als Supplement verfügbar.'),
  ('milchsaeurebakterien-qps', 'Milchsäurebakterien (QPS)', 'Lactic acid bacteria (QPS)', 'QPS-gelistete Milchsäurebakterien wie P. acidilactici, Lactobacillus, Leuconostoc. Vereinfachte Sicherheitsbewertung.'),
  ('enterokokken-community-clade', 'Enterokokken Community Clade', 'Enterococci Community Clade', 'E. lactis (früher E. faecium Clade B): Sichere Community-assoziierte Stämme OHNE Hospital-Marker. SF68 gehört hierzu.'),
  ('pediococcus-qps', 'Pediococcus (QPS)', 'Pediococcus (QPS)', 'QPS-gelistete Pediococcus-Arten: P. pentosaceus und P. acidilactici. Beide haben vereinfachte Sicherheitsbewertung.'),
  ('starterkulturen-kaese', 'Starterkulturen (Käserei)', 'Starter cultures (dairy)', 'Traditionelle Käserei-Starterkulturen wie L. lactis, L. cremoris, Leuconostoc. Jahrtausendealte Sicherheitshistorie.'),
  ('nisin-produzenten', 'Nisin-Produzenten', 'Nisin producers', 'Nur L. lactis kann natürlich Nisin produzieren. Nisin (E234) ist zugelassenes Lebensmittelkonservierungsmittel.'),
  ('leuconostoc-qps', 'Leuconostoc (QPS)', 'Leuconostoc (QPS)', 'QPS-gelistete Leuconostoc-Arten: L. mesenteroides, L. citreum, L. lactis, L. pseudomesenteroides. KEINE humane probiotische Evidenz!'),
  ('propionibacterium-qps', 'Propionibacterium (QPS)', 'Propionibacterium (QPS)', 'QPS-gelistete Propionibacterium-Arten: P. freudenreichii, A. acidipropionici. NICHT verwechseln mit Cutibacterium acnes (pathogen)!'),
  ('b12-produzenten', 'B12-Produzenten', 'B12 producers', 'P. freudenreichii ist EINZIGER Probiotikum mit natürlicher Vitamin B12-Produktion. Winclove W200 hat EU-B12-Claims.'),
  ('heterofermentative', 'Heterofermentative LAB', 'Heterofermentative LAB', 'Leuconostoc = obligat heterofermentativ (produziert CO2). Unterschied zu homofermentativen Lactobacillus/Lactococcus.'),
  ('ecn-probiotika', 'E. coli Nissle (Arzneimittel)', 'E. coli Nissle (pharmaceutical)', 'EcN ist in DACH als Arzneimittel zugelassen (Mutaflor®). KEIN QPS-Status. Einziges Probiotikum mit ECCO-Empfehlung für UC.'),
  ('butyrat-produzenten', 'Butyrat-Produzenten', 'Butyrate producers', 'C. butyricum ist primärer Butyrat-Produzent. ~70% der Kolonozyten-Energie aus Butyrat. Anti-inflammatorisch via HDAC-Inhibition.'),
  ('ici-adjuvans', 'ICI-Adjuvans (Onkologie)', 'ICI adjuvant (oncology)', 'CBM588 verstärkt Checkpoint-Inhibitor-Wirksamkeit bei mRCC (Dizman 2022: HR 0,15!). Einzigartige onkologische Anwendung.'),
  ('novel-food-probiotika', 'Novel Food Probiotika', 'Novel Food probiotics', 'C. butyricum CBM588 (2014), TO-A (2025). Kein QPS, aber EU Novel Food zugelassen mit Mengenbegrenzung.'),
  ('Präbiotika', 'Präbiotika', 'Prebiotics', 'Nicht verdauliche Substanzen, die selektiv das Wachstum nützlicher Darmbakterien fördern. FOS, Inulin, GOS.'),
  ('fructane', 'Fructane', 'Fructans', 'Fructose-Polymere: FOS (kurzkettig) und Inulin (langkettig). HIGH-FODMAP!'),
  ('synbiotika-komponenten', 'Synbiotika-Komponenten', 'Synbiotic components', 'Substanzen für Synbiotika-Formulierungen: Präbiotika (FOS, GOS, Inulin) + Probiotika.'),
  ('fodmap-high', 'High-FODMAP', 'High-FODMAP', '⚠️ Bei IBS kontraindiziert: FOS, Inulin, GOS, Lactulose, Fruktose, Laktose, Polyole.'),
  ('Ballaststoffe', 'Fermentierbare Ballaststoffe', 'Fermentable fibers', 'Im Dickdarm fermentiert → SCFA-Produktion. FOS, Inulin, Pektin, Beta-Glucan.'),
  ('konjugierte-fettsaeuren', 'Konjugierte Fettsäuren', 'Conjugated fatty acids', 'Fettsäuren mit konjugierten Doppelbindungen: CLA, CLnA (Punizinsäure, α-Eleostearinsäure). Besondere biologische Aktivität über PPARs.'),
  ('clna', 'Konjugierte Linolensäuren (CLnA)', 'Conjugated linolenic acids', 'C18:3 mit konjugierten Doppelbindungen: Punizinsäure, α-Eleostearinsäure, Calendulasäure, Jacarinsäure, Catalpasäure.'),
  ('spezialöele', 'Spezialöle / Nischenöle', 'Specialty oils', 'Seltene pflanzliche Öle mit besonderen Fettsäureprofilen: Granatapfelsamenöl, Tungöl, Ringelblumenöl.'),
  ('novel-food-oel', 'Novel Food (Öle)', 'Novel Food (oils)', '⚠️ Öle ohne Verwendungshistorie vor 1997 in EU: PSO, einige exotische Samenöle. Zulassungspflicht!'),
  ('ppar-agonisten', 'PPARγ-Agonisten (natürlich)', 'Natural PPARγ agonists', 'Natürliche Substanzen mit PPARγ-Aktivität: Punizinsäure, CLA, einige Flavonoide.'),
  ('c6-capronsaeure', 'Capronsäure (C6)', 'Caproic Acid', 'Kürzeste MCT (6 C). Wird aus Produkten ENTFERNT wegen GI-Nebenwirkungen und Geruch. "C6-frei" = Qualitätsmerkmal.'),
  ('c8-caprylsaeure', 'Caprylsäure (C8)', 'Caprylic Acid', 'Goldstandard für Ketose. 3x ketogener als C10, 6x ketogener als C12. Geschmacksneutral, gut verträglich.'),
  ('c10-caprinsaeure', 'Caprinsäure (C10)', 'Capric Acid', 'Zweitketogenste MCT. Zusätzlich: Direkte AMPA-Rezeptor-Hemmung (antikonvulsiv). Oft in C8+C10 Mischungen.'),
  ('c12-laurinsaeure', 'Laurinsäure (C12)', 'Lauric Acid', '⚠️ Technisch MCT, aber metabolisch wie LCT! 45-50% von Kokosöl. Weniger ketogen als C8/C10.'),
  ('ketogene-supplements', 'Ketogene Supplements', 'Ketogenic Supplements', 'Supplements zur Unterstützung der Ketose: MCT-Öl, exogene Ketone, etc.'),
  ('mct-einzelfettsaeuren', 'MCT-Einzelfettsäuren', 'Individual MCT Fatty Acids', 'Die 4 MCT-Fettsäuren als Einzelsubstanzen: C6 (Capronsäure), C8 (Caprylsäure), C10 (Caprinsäure), C12 (Laurinsäure).'),
  ('ketogene-hilfsmittel', 'Ketogene Hilfsmittel', 'Ketogenic Aids', 'Supplements zur Unterstützung der Ketose: C8-Öl, MCT-Öl, exogene Ketone, BHB-Salze.'),
  ('alzheimer-adjuvant', 'Alzheimer-Adjuvantien', 'Alzheimer Adjuvants', 'Supplements mit Evidenz bei MCI/Alzheimer. C8 nur für APOE4-NEGATIVE Patienten!'),
  ('apoe4-relevant', 'APOE4-relevante Supplements', 'APOE4-relevant Supplements', 'Supplements mit genotyp-abhängiger Wirkung. APOE4-Testung vor Einsatz sinnvoll.'),
  ('ampa-antagonisten', 'AMPA-Rezeptor-Antagonisten', 'AMPA Receptor Antagonists', 'Substanzen die AMPA-Glutamatrezeptoren hemmen. Antikonvulsive Wirkung. C10 und Perampanel wirken synergistisch (unterschiedliche Bindungsstellen).'),
  ('epilepsie-adjuvantien', 'Epilepsie-Adjuvantien', 'Epilepsy Adjuvants', 'Substanzen zur Unterstützung der Epilepsie-Therapie. C10 > C8 für Epilepsie aufgrund AMPA-Hemmung.'),
  ('mct-fuer-neurologie', 'MCT für Neurologie', 'MCT for Neurology', 'MCT-Anwendungen bei neurologischen Erkrankungen. C10 für Epilepsie (AMPA), C8 für Alzheimer (Ketone, nur APOE4-negativ).'),
  ('pseudo-mct', 'Pseudo-MCT', 'Pseudo-MCT', 'Fettsäuren die als MCT vermarktet werden, aber metabolisch wie LCFA wirken. C12 (Laurinsäure) ist das Hauptbeispiel - braucht Carnitin-Shuttle!'),
  ('antimikrobielle-fettsaeuren', 'Antimikrobielle Fettsäuren', 'Antimicrobial Fatty Acids', 'Fettsäuren mit nachgewiesener antimikrobieller Wirkung. Ranking: C12 > C10 > C8 (Kabara 1972). Monolaurin ist bis zu 200x potenter als freie C12.'),
  ('kokosoel-derivate', 'Kokosöl-Derivate', 'Coconut Oil Derivatives', 'Produkte aus Kokosöl: Natives Kokosöl, MCT-Öl, Monolaurin. Unterschiedliche Anwendungen beachten!'),
  ('cholesterin-erhoehend', 'Cholesterin-erhöhende Substanzen', 'Cholesterol-raising Substances', 'Substanzen die LDL erhöhen. C12/Kokosöl erhöht LDL um ~10 mg/dL. Bei Hypercholesterinämie Vorsicht!'),
  ('kokosoel', 'Kokosöl', 'Coconut Oil', 'Pflanzenöl aus Kokosnuss. 82-92% gesättigte Fette. ⚠️ AHA/Harvard warnen: Erhöht LDL! Nur 13-15% echte MCT. Beste Anwendung: TOPISCH (Haut, Haare).'),
  ('palmkernoel', 'Palmkernöl', 'Palm Kernel Oil', 'Öl aus Ölpalm-KERN (nicht Fruchtfleisch!). Ähnlich Kokosöl, aber weniger MCT (~7%) und MASSIVE Umweltprobleme. NICHT als Supplement empfohlen.'),
  ('laurische-oele', 'Laurische Öle', 'Lauric Oils', 'Öle mit hohem Laurinsäure-Gehalt (C12): Kokosöl, Palmkernöl. Erhöhen LDL-Cholesterin. Laurinsäure ist metabolisch eher LCFA als MCT.'),
  ('topische-anwendung', 'Topische Anwendung', 'Topical Application', 'Anwendung auf der Haut/Haaren statt orale Einnahme. Für Kokosöl: BESTE Evidenz ist topisch (atopische Dermatitis, Haarpflege).'),
  ('gesaettigte-fette-warnung', 'Gesättigte Fette - Warnung', 'Saturated Fat Warning', 'AHA/DGE empfehlen Begrenzung. Kokosöl = 82-92% gesättigt, mehr als Butter (63%)! Erhöht LDL-Cholesterin.'),
  ('regenwald-zerstoerung', 'Regenwald-Zerstörung', 'Rainforest Destruction', 'Hauptsächlich Palmöl/Palmkernöl. 60% der Expansion auf Primär-Regenwald. RSPO-Zertifizierung umstritten.'),
  ('Phospholipide', 'Phospholipide', 'Phospholipids', 'Lipide mit Phosphatgruppe. Hauptbestandteile von Zellmembranen. PS, PC, PE, PI.'),
  ('Nootropika', 'Nootropika', 'Nootropics', 'Substanzen zur Unterstützung kognitiver Funktionen. PS, Alpha-GPC, Bacopa, etc.'),
  ('Cholin-Verbindungen', 'Cholin-Quellen', 'Choline Sources', 'Supplemente die Cholin liefern: PC (~13%), Alpha-GPC (~40%), CDP-Cholin (~18%), Cholinbitartrat (~41%).'),
  ('Leber-Support', 'Lebergesundheit', 'Liver Health', 'Substanzen für Leberfunktion. Cholin/PC essenziell für VLDL-Synthese. EFSA-Claim zugelassen.'),
  ('cortisol-modulation', 'Cortisol-Modulation', 'Cortisol Modulation', 'Substanzen die Cortisol-Antwort beeinflussen: PS, Ashwagandha, Rhodiola.'),
  ('fda-qualified-claims', 'FDA Qualified Health Claims', 'FDA Qualified Health Claims', 'Substanzen mit FDA-qualifizierten Claims. PS: einzige Substanz für Kognition!'),
  ('efsa-claims-abgelehnt', 'EFSA Claims abgelehnt', 'EFSA Claims Rejected', 'Substanzen deren Health Claims von EFSA abgelehnt wurden (trotz möglicher Evidenz).'),
  ('phosphatidylethanolamin', 'Phosphatidylethanolamin (PE)', 'Phosphatidylethanolamine', 'Zweitgrößtes Membran-Phospholipid. Essentiell für Autophagie (LC3-PE). ⚠️ NISCHENPRODUKT ohne Humanstudien!'),
  ('phosphatidylinositol', 'Phosphatidylinositol (PI)', 'Phosphatidylinositol', 'Signalmolekül-Vorläufer (PIP2, PIP3). ⚠️ Wird hydrolysiert! Myo-Inositol ist als Supplement ÜBERLEGEN!'),
  ('autophagie-supplements', 'Autophagie-Supplements', 'Autophagy Supplements', 'Substanzen die Autophagie fördern: PE (präklinisch), Spermidin (mehr Evidenz), Fasten-Mimetika.'),
  ('nischenprodukte', 'Nischenprodukte (wenig Evidenz)', 'Niche Products (Limited Evidence)', 'Supplements mit theoretischem Potenzial aber fehlenden Humanstudien. PE, PI gehören dazu.'),
  ('inositol-derivate', 'Inositol-Derivate', 'Inositol Derivatives', 'PI, Myo-Inositol, D-chiro-Inositol. ⭐ Myo-Inositol hat beste Evidenz (PCOS, Metabolismus).'),
  ('membran-phospholipide', 'Membran-Phospholipide', 'Membrane Phospholipids', 'PC (40-50%), PE (15-25%), PS (5-10%), PI (~5%). Strukturelle und funktionelle Bedeutung.'),
  ('praeklinisch-vielversprechend', 'Präklinisch vielversprechend', 'Preclinically Promising', 'Substanzen mit starken Tier-/Zelldaten aber fehlenden Humanstudien. PE für Autophagie ist Beispiel.'),
  ('lecithin', 'Lecithin (Mischung)', 'Lecithin (Mixture)', 'MISCHUNG aus PC, PE, PI, PA, PS. E322. NICHT mit PC gleichsetzen! EFSA: Alle Claims abgelehnt.'),
  ('emulgatoren', 'Emulgatoren (E-Nummern)', 'Emulsifiers', 'Lecithin (E322) als Lebensmittelzusatzstoff. Quantum Satis in den meisten Lebensmitteln.'),
  ('soja-produkte', 'Soja-Produkte', 'Soy Products', 'Soja-basierte Supplemente. ⚠️ Allergenkennzeichnung! 94% GVO global.'),
  ('allergenfreie-alternativen', 'Allergenfreie Alternativen', 'Allergen-Free Alternatives', 'Sonnenblumen-Lecithin, Raps-Lecithin als Soja-Alternativen.'),
  ('gvo-frei', 'GVO-frei / Non-GMO', 'Non-GMO', 'Non-GVO, IP (Identity Preserved), Bio-zertifiziert. Für Clean-Label wichtig.'),
  ('cochrane-negativ', 'Cochrane-negativ', 'Cochrane Negative', 'Substanzen mit negativem Cochrane Review. Lecithin für Demenz (2003).'),
  ('Kohlenhydrate', 'Oligosaccharide', 'Oligosaccharides', 'Kurzkettige Kohlenhydrate (DP 2-10). GOS, FOS, HMOs.'),
  ('saeuglings-supplemente', 'Säuglings-Supplemente', 'Infant Supplements', 'Für Säuglingsnahrung zugelassen. GOS/FOS, HMOs, Nukleotide.'),
  ('fodmap', 'FODMAP-Substanzen', 'FODMAPs', 'Fermentierbare Oligo-, Di-, Monosaccharide und Polyole. Bei IBS oft problematisch. GOS, FOS, Laktose, Fruktose.'),
  ('mikrobiom-modulation', 'Mikrobiom-Modulation', 'Microbiome Modulation', 'Substanzen zur gezielten Beeinflussung des Darmmikrobioms. Präbiotika, Probiotika, Synbiotika.'),
  ('praebiotika-niedrigdosis', 'Niedrigdosis-Präbiotika', 'Low-Dose Prebiotics', 'Präbiotika mit besonders niedriger Wirkdosis. XOS: 1,4-2,8 g/Tag vs. 5-10 g bei GOS/FOS/Inulin.'),
  ('pentose-oligosaccharide', 'Pentose-Oligosaccharide', 'Pentose Oligosaccharides', 'Oligosaccharide aus C5-Zuckern (Xylose). XOS ist das Hauptbeispiel.'),
  ('novel-food-2018', 'Novel Food (EU 2018+)', 'Novel Food (EU 2018+)', 'Nach 2018 zugelassene Novel Foods. XOS: VO 2018/1648.'),
  ('pflanzliche-praebiotika', 'Pflanzliche Präbiotika', 'Plant-Based Prebiotics', 'Präbiotika aus pflanzlichen Quellen (nicht Milch). XOS, FOS, Inulin. Vegan.'),
  ('langsam-verdauliche-kohlenhydrate', 'Langsam verdauliche Kohlenhydrate', 'Slowly Digestible Carbohydrates', '⚠️ Kohlenhydrate die langsam, aber VOLLSTÄNDIG verdaut werden. IMO gehört hierzu - NICHT zu Ballaststoffen!'),
  ('pseudo-praebiotika', 'Pseudo-Präbiotika', 'Pseudo-Prebiotics', '⚠️ Substanzen die als Präbiotika VERMARKTET werden, aber wissenschaftlich NICHT als solche gelten. IMO = Hauptbeispiel.'),
  ('fda-abgelehnte-ballaststoffe', 'FDA-abgelehnte "Ballaststoffe"', 'FDA-Rejected "Fibers"', '⚠️ Substanzen deren Ballaststoff-Status von FDA abgelehnt wurde. IMO seit 2018/2020.'),
  ('efsa-abgelehnte-claims', 'EFSA-abgelehnte Claims', 'EFSA-Rejected Claims', 'Substanzen deren Health Claims von EFSA abgelehnt wurden. IMO: ID 798, 800 abgelehnt.'),
