  ('efsa-cholesterin-claims', 'EFSA Cholesterin-Claims', 'EFSA Cholesterol Claims', '⭐ Substanzen mit zugelassenen EFSA Health Claims für Cholesterinsenkung: Hafer-BG (3g), Gerste-BG (3g), Pektin (6g).'),
  ('efsa-blutzucker-claims', 'EFSA Blutzucker-Claims', 'EFSA Blood Glucose Claims', '⭐ Substanzen mit zugelassenen EFSA Health Claims für Blutzucker: Hafer-BG (4g/30g Carbs), Pektin (10g/Mahlzeit).'),
  ('immunmodulatoren-beta-glucan', 'Immunmodulatoren (Beta-Glucan)', 'Immunomodulators (Beta-Glucan)', '⭐ NUR β-1,3/1,6-Glucane (Pilze, Hefe) wirken immunmodulierend via Dectin-1. Getreide-Glucane NICHT!'),
  ('novel-food-zugelassen', 'Novel Food zugelassen', 'Novel Food Approved', '⭐ EU Novel Food zugelassene Substanzen: Hefe-Beta-Glucan (Wellmune, max. 375 mg/Tag).'),
