  ('fertilitaet', 'Fertilitaet', 'Fertility', 'Supplements fuer maennliche/weibliche Fertilitaet, Spermienqualitaet.'),
  ('ashwagandha-extrakte', 'Ashwagandha-Extrakte', 'Ashwagandha Extracts', '⭐ Standardisierte Extrakte aus Withania somnifera. KSM-66 (Wurzel), Sensoril (Wurzel+Blatt), Shoden (hochkonzentriert).'),
  ('ksm66-spezifisch', 'KSM-66 Anwendungen', 'KSM-66 Applications', '⭐⭐ Meistuntersuchter Extrakt. BESTE WAHL fuer: Sport, Kraft, Testosteron, Fertilitaet, morgendliche Stressreduktion.'),
  ('sensoril-spezifisch', 'Sensoril Anwendungen', 'Sensoril Applications', '⭐ Dreifach-standardisiert. BESTE WAHL fuer: Schlaf, abendliche Entspannung, Angst, Schizophrenie-Adjunktiv.'),
  ('maennliche-gesundheit', 'Maennliche Gesundheit', 'Male Health', 'Supplements fuer Testosteron, Fertilitaet, Spermienqualitaet, Libido. KSM-66 bevorzugt.'),
  ('schlaf', 'Schlaf', 'Sleep', 'Supplements fuer Schlafqualitaet, Einschlafen, Durchschlafen. Sensoril oder Shoden abends.'),
  ('bulk-laxanzien', 'Bulk-forming Laxanzien', 'Bulk-forming Laxatives', 'Ballaststoffe die durch Volumenzunahme und Wasserretention die Darmpassage fördern (Psyllium, Methylcellulose).'),
  ('osmotische-laxanzien', 'Osmotische Laxanzien', 'Osmotic Laxatives', 'Substanzen die Wasser im Darm halten (Lactulose, Lactitol, Macrogol/PEG).'),
  ('polyole', 'Zuckeralkohole / Polyole', 'Sugar Alcohols / Polyols', 'Kalorienreduzierte Süßungsmittel wie Lactitol (E966), Sorbitol (E420), Xylitol (E967).'),
  ('suessungsmittel', 'Süßungsmittel', 'Sweeteners', 'Zuckerersatzstoffe zur Reduktion von Kalorien/Zucker in Lebensmitteln.'),
  ('rhodiola-anwendungen', 'Rhodiola-Anwendungen', 'Rhodiola Applications', '⭐⭐ EMA-zugelassen für Stress! BESTE WAHL für: Burnout, akute Fatigue, Prüfungsstress, leichte Depression, akute Sportleistung. MORGENS einnehmen!'),
  ('ginseng-anwendungen', 'Ginseng-Anwendungen', 'Ginseng Applications', '⭐ Klassisches Tonikum. BESTE WAHL für: Cancer-Related Fatigue (Phase III!), ED, Immunsystem, langfristige Kognition, Diabetes-Unterstützung.'),
  ('stress-burnout', 'Stress & Burnout', 'Stress & Burnout', 'Supplements für Stressreduktion, HPA-Achsen-Balance, Burnout-Prävention. Rhodiola = Goldstandard (EMA).'),
  ('kognition-nootropika', 'Kognition & Nootropika', 'Cognition & Nootropics', 'Supplements für Gedächtnis, Konzentration, mentale Klarheit. Rhodiola akut, Ginseng langfristig.'),
  ('energie-fatigue', 'Energie & Fatigue', 'Energy & Fatigue', 'Supplements gegen Müdigkeit und Erschöpfung. Rhodiola schnell, Ginseng aufbauend. Bei Krebs: Ginseng!'),
  ('maennergesundheit', 'Männergesundheit', 'Mens Health', 'Supplements für ED, Testosteron, Prostata. Ginseng für ED (Cochrane-bestätigt).'),
  ('depression-stimmung', 'Depression & Stimmung', 'Depression & Mood', 'Supplements für Stimmungsaufhellung. Rhodiola bei leichter Depression als SSRI-Alternative (weniger NW).'),
  ('stoffwechsel-diabetes', 'Stoffwechsel & Diabetes', 'Metabolism & Diabetes', 'Supplements für Blutzuckerkontrolle. Ginseng senkt Nüchtern-BZ und HbA1c moderat.'),
  ('pflanzengummen', 'Pflanzengummen / Hydrokolloid', 'Plant Gums / Hydrocolloids', 'Natürliche Polysaccharide aus Pflanzenexsudaten (Gummi arabicum, Guarkernmehl, Xanthan).'),
  ('echte-ginseng-arten', 'Echte Ginseng-Arten (Panax)', 'True Ginseng Species (Panax)', '⭐ Nur Panax-Arten sind ECHTER Ginseng: P. ginseng (Koreanisch), P. quinquefolius (Amerikanisch), P. notoginseng (Sanchi). Enthalten Ginsenoside.'),
  ('falsche-ginseng', '⚠️ "Falsche" Ginseng-Bezeichnungen', 'False Ginseng Names', '⚠️ KEIN echter Ginseng: Sibirischer "Ginseng" (Eleutherococcus), Brasilianischer "Ginseng" (Pfaffia), Indischer "Ginseng" (Ashwagandha). Andere Wirkstoffe!'),
  ('panax-quinquefolius-anwendungen', 'Amerikanischer Ginseng Anwendungen', 'American Ginseng Applications', '⭐⭐ BESTE EVIDENZ: Kognition (CEREBOOST®), Cancer-Related Fatigue (Phase III!), Diabetes/Blutzucker (Vuksan). TCM: "Kühlend" (Yin).'),
  ('eleutherococcus-anwendungen', 'Sibirischer Ginseng Anwendungen', 'Siberian Ginseng Applications', '⚠️ EVIDENZ UNZUREICHEND! Sowjetische Claims in modernen RCTs NICHT bestätigt. Einzig Immunmodulation zeigt begrenzte Evidenz (Bohn 1987).'),
  ('kognition-arbeitsgedaechtnis', 'Kognition & Arbeitsgedächtnis', 'Cognition & Working Memory', '⭐⭐ CEREBOOST® (P. quinquefolius) = Goldstandard. Akute Effekte 1-6h. Eleuthero: KEINE Kognitions-Evidenz!'),
  ('cancer-fatigue', 'Cancer-Related Fatigue', 'Cancer-Related Fatigue', '⭐⭐⭐ P. quinquefolius 2 g/Tag = BESTE EVIDENZ (Barton 2013 Phase III). Eleuthero: KEINE Evidenz.'),
  ('blutzucker-diabetes', 'Blutzucker & Diabetes', 'Blood Sugar & Diabetes', '⭐⭐ P. quinquefolius: HbA1c -0,29%, Nüchtern-BZ -0,71 mmol/L (Vuksan). Meta-Analyse bestätigt. Cave: Hypoglykämie!'),
  ('adaptogene-kritik', 'Adaptogene - Kritische Bewertung', 'Adaptogens - Critical Evaluation', '⚠️ "Adaptogen" ist KEIN Wirksamkeitsnachweis! Brekhman-Kriterien (1968) oft nicht in modernen RCTs bestätigt. Eleuthero = Paradebeispiel für Evidenz-Lücke.'),
  ('ginseng-vergleich', 'Ginseng-Arten Vergleich', 'Ginseng Species Comparison', '⭐ P. quinquefolius: Kühlend, PPD-dominant, Rb1/Rg1>5, F11-Marker. P. ginseng: Wärmend, PPT-dominant, Rb1/Rg1<5, Rf-Marker. E. senticosus: KEIN Ginseng!'),
  ('hemicellulosen', 'Hemicellulosen', 'Hemicelluloses', 'Pflanzliche Zellwandpolysaccharide inkl. Arabinoxylan, Xylan, Mannan.'),
  ('quellstoffe', 'Quellstoffe / Bulk-Laxanzien', 'Bulk-Forming Laxatives', 'Ballaststoffe die durch Wasseraufnahme quellen (Psyllium, Glucomannan).'),
  ('ayurvedische-adaptogene', 'Ayurvedische Adaptogene', 'Ayurvedic Adaptogens', '⭐ Adaptogene aus der ayurvedischen Tradition: Tulsi (Königin der Kräuter), Ashwagandha, Brahmi. >3.000 Jahre Anwendungsgeschichte.'),
  ('tulsi-varietaeten', 'Tulsi-Varietäten (KRITISCH!)', 'Tulsi Varieties (CRITICAL!)', '⚠️⚠️ KRITISCHE UNTERSCHEIDUNG: Rama (grün) = SICHER (0,87-1,94% Methyleugenol). Krishna (lila) = GEFÄHRLICH (67-92% Methyleugenol)!'),
  ('methyleugenol-risiko', '⚠️ Methyleugenol-Risikosubstanzen', 'Methyleugenol Risk Substances', '⚠️⚠️ Methyleugenol = genotoxisches Karzinogen (IARC 2B, NTP, EU-SCF). KEIN sicherer Schwellenwert! Betrifft: Krishna Tulsi, Lemongras, Tarragon, Basilikum-ÖL.'),
  ('stress-adaptogene', 'Stress-Adaptogene', 'Stress Adaptogens', '⭐ Adaptogene mit Stress-Evidenz: Ashwagandha (stärkste Angst-Evidenz), Tulsi (37% Stress↓, 36% Cortisol↓), Rhodiola (Fatigue). Verschiedene Wirkmechanismen.'),
  ('blutzucker-supplements', 'Blutzucker-Supplements', 'Blood Sugar Supplements', '⭐ Tulsi: Beste Blutzucker-Evidenz unter Adaptogenen (-15,7 mg/dL Nüchtern-BZ). Auch: Berberin, Zimt, Chrom. Cave: Hypoglykämie bei Antidiabetika!'),
  ('immunmodulatoren-pflanzlich', 'Pflanzliche Immunmodulatoren', 'Herbal Immunomodulators', '⭐ Tulsi: Einzigartig antimikrobiell + immunmodulatorisch (NK-Zellen↑, IFN-γ↑). Auch: Echinacea, Holunder, Astragalus.'),
  ('hepatotoxizitaets-bedenken', '⚠️ Hepatotoxizitäts-Bedenken', 'Hepatotoxicity Concerns', '⚠️ Ashwagandha: 70+ Fälle von Leberschädigung dokumentiert! Tulsi: KEINE Hepatotoxizität dokumentiert - daher sicherere Alternative für Langzeitanwendung.'),
  ('schwangerschaft-kontraindiziert', '❌ In Schwangerschaft kontraindiziert', 'Contraindicated in Pregnancy', '❌❌ Tulsi: Anti-Implantation, Fertilitätsstörungen im Tierversuch. Auch: Ashwagandha, Dong Quai, Mutterkraut. NIEMALS bei Schwangerschaft/Kinderwunsch!'),
  ('antikoagulantien-interaktion', '⚠️ Antikoagulantien-Interaktion', 'Anticoagulant Interaction', '⚠️ Tulsi (Eugenol): Thrombozyten-Hemmung → Blutungsrisiko. Auch: Ginkgo, Knoblauch, Omega-3, Vitamin E. 2 Wochen vor OP absetzen!'),
  ('adaptogen-vergleich', 'Adaptogene im Vergleich', 'Adaptogens Comparison', '⭐ Ashwagandha: Stärkste Angst-Evidenz, aber Lebertoxizität. Rhodiola: Schnell, stimulierend, für Fatigue. Tulsi: Beruhigend, antimikrobiell, metabolisch. Eleuthero: Evidenz SCHWACH!'),
  ('beta-glucane', 'Beta-Glucane', 'Beta-Glucans', 'Polysaccharide aus Glucose mit β-glykosidischen Bindungen. Hafer: β-1,3/1,4 (metabolisch). Pilze: β-1,3/1,6 (immunmodulatorisch).'),
  ('resistente-staerke', 'Resistente Stärke / Dextrine', 'Resistant Starch / Dextrins', 'Stärke die im Dünndarm nicht verdaut wird (RS1-RS4). Weizendextrin = RS4.'),
  ('herz-kreislauf', 'Herz-Kreislauf-Supplements', 'Cardiovascular Supplements', 'Nahrungsergänzungen für Herzgesundheit (Omega-3, Beta-Glucan, Phytosterole).'),
  ('tcm-adaptogene', 'TCM-Adaptogene', 'TCM Adaptogens', '⭐ Adaptogene aus der TCM: Schisandra (Wu Wei Zi), Ginseng (Ren Shen), Astragalus (Huang Qi). >2.000 Jahre Anwendungsgeschichte.'),
  ('sowjetische-adaptogene', 'Sowjetische Adaptogen-Forschung', 'Soviet Adaptogen Research', '⚠️ Brekhman/Lazarev (1947-1969): Schisandra, Eleuthero, Rhodiola. Historisch wichtig, aber methodisch nach modernen Standards unzureichend.'),
  ('hepatoprotektion-unique', '⭐ Hepatoprotektion (Schisandra-Alleinstellungsmerkmal)', 'Hepatoprotection (Schisandra Unique)', '⭐⭐ EINZIGARTIG unter Adaptogenen! Schisandra: GSH↑ 2,6-8×, Phase-II-Enzyme↑ 2,5-5×, Nrf2-Aktivierung. Meta-Analyse Tier: ALT/AST↓↓.'),
  ('cyp-interaktionen-kritisch', '⚠️⚠️ CYP450-Interaktionen (KRITISCH!)', 'CYP450 Interactions (CRITICAL!)', '⚠️⚠️⚠️ Schisandra = STÄRKSTE CYP3A4-Hemmung aller Adaptogene! Gomisin C IC50=0,049 µM. Tacrolimus +164%! LEBENSGEFAHR bei Immunsuppression!'),
  ('adapt-232-kombination', 'ADAPT-232 Kombination', 'ADAPT-232 Combination', '⭐ Rhodiola + Schisandra + Eleuthero. Klinisch validiert für Fatigue, Kognition, Long-COVID. Synergistische Hsp70-Induktion.'),
  ('menopause-phyto', 'Phytotherapie Menopause', 'Phytotherapy Menopause', '⭐ Schisandra BMO-30: RCT-validiert (Kupperman-Index↓). Auch: Traubensilberkerze, Rotklee, Maca. Cave: CYP-Interaktionen mit HRT!'),
  ('sarkopenie-alter', 'Sarkopenie und Muskelkraft im Alter', 'Sarcopenia and Muscle Strength in Elderly', '⭐ Schisandra 1000 mg/Tag: 2 RCTs zeigen Quadrizeps-Kraft↑ ohne Muskelmassezunahme. Auch: Kreatin, Vitamin D, Protein.'),
  ('lignane-phytochemie', 'Lignane (Phytochemie)', 'Lignans (Phytochemistry)', '⭐ Dibenzocyclooctadien-Lignane = Schisandra-spezifisch! >86 verschiedene. Schisandrin, Gomisin, Deoxyschisandrin. Lipophil, CYP-Interaktion.'),
  ('transplantation-kontraindiziert', '❌ Bei Transplantation KONTRAINDIZIERT', 'CONTRAINDICATED in Transplantation', '❌❌❌ Schisandra + Tacrolimus/Cyclosporin = LEBENSGEFAHR! AUC +164-293%! NIEMALS bei Organtransplantation!'),
  ('Vitalpilze', 'Vitalpilze / Medizinalpilze', 'Medicinal Mushrooms', '⭐ Cordyceps, Reishi, Lions Mane, Chaga, Shiitake, Maitake. Polysaccharide (β-Glucane), Triterpene. Immunmodulation, Energie, Kognition.'),
  ('cordyceps-arten', '⭐ Cordyceps-Arten (KRITISCH!)', 'Cordyceps Species (CRITICAL!)', '⭐⭐ C. militaris (kultiviert) = EMPFOHLEN! 5-15× mehr Cordycepin, verfügbar, sicher. O. sinensis (wild) = PROBLEMATISCH! Teuer, 70% verfälscht, Schwermetalle. Cs-4 = RCT-validiert.'),
  ('verfaelschung-kritisch', '⚠️⚠️ Verfälschungsproblematik', 'Adulteration Problem', '⚠️⚠️⚠️ 70% der O. sinensis-Produkte VERFÄLSCHT! Mehl, Metalldrähte, Bleisulfat, andere Pilze. DNA-Barcoding zeigt: Nur 30% korrekte Spezies. IMMER C. militaris bevorzugen!'),
  ('ausdauer-aeltere', '⭐ Ausdauer bei Älteren (Cordyceps-Stärke)', 'Endurance in Elderly (Cordyceps Strength)', '⭐⭐ BESTE EVIDENZ für Cordyceps! Chen 2010: +10,5% metabolische Schwelle bei 50-75-Jährigen. Bei jungen Trainierten: KEINE Evidenz!'),
  ('nierenerkrankung-adjuvant', '⭐⭐ Nierenerkrankungen adjuvant (Cochrane!)', 'Kidney Disease Adjunctive (Cochrane!)', '⭐⭐ COCHRANE-REVIEW (22 RCTs): Cs-4/Bailing + Standardtherapie überlegen! Kreatinin↓, Clearance↑, Proteinurie↓. BESTE Cordyceps-Evidenz!'),
  ('immunsuppression-kontraindiziert', '⚠️⚠️ Bei Immunsuppression KONTRAINDIZIERT', 'CONTRAINDICATED in Immunosuppression', '⚠️⚠️ Cordyceps schützt Immunzellen vor Immunsuppressiva! Vermindert deren Wirksamkeit! NICHT bei Transplantation!'),
  ('libido-keine-evidenz', '⚠️ Libido/Sexualfunktion - KEINE Humanstudien!', 'Libido - NO Human Studies!', '⚠️⚠️ Trotz starker Marketing-Claims: KEINE EINZIGE RCT zur Sexualfunktion am Menschen publiziert! Nur In-vitro/Tiermodelle!'),
  ('diabetes-keine-evidenz', '⚠️ Diabetes - KEINE Humanstudien!', 'Diabetes - NO Human Studies!', '⚠️⚠️ Tiermodelle zeigen -85% Blutzucker, aber KEINE Humanstudien! NICHT für Diabetes empfehlen!'),
  ('myzel-auf-getreide-problem', '⚠️ Myzel-auf-Getreide (MOG) Problem', 'Mycelium on Grain (MOG) Problem', '⚠️ MOG-Produkte enthalten 35-40% STÄRKE aus unverdautem Getreide! Niedrige Wirkstoffgehalte. "Polysaccharide" = oft nur Stärke! FRUCHTKÖRPER bevorzugen!'),
