  ('aphrodisiakum-traditionell', '⚠️ Aphrodisiakum (traditionell)', 'Aphrodisiac (Traditional)', '⚠️ Epimedium: Traditionelle TCM-Verwendung für Potenz/Libido. KEINE Human-RCTs!'),
  ('serm-phytoestrogen', 'SERM / Phytoöstrogen', 'SERM / Phytoestrogen', 'Epimedium: SERM-ähnliche Aktivität. Östrogenrezeptor-Modulation über nicht-genomische Wege. Interessant für Knochen.'),
  ('osteogen-knochen', '⭐ Osteogen / Knochengesundheit', 'Osteogenic / Bone Health', '⭐ Epimedium: EINZIGE moderate Evidenz (Zhang 2007). Unterstützt Knochendichte bei postmenopausalen Frauen.'),
  ('novel-food-eu', '❌ Novel Food (EU)', 'Novel Food (EU)', '❌ Epimedium-Extrakt: Novel Food in EU. Verkauf ohne Zulassung nicht rechtmäßig.'),
