  ('marketing-vs-evidenz', '❌❌ Marketing vs. Evidenz', 'Marketing vs. Evidence', '❌❌ Epimedium: Als "natürliches Viagra" vermarktet, aber KEINE Human-RCTs für ED/Libido/Testosteron!'),
  ('pflanzliche-extrakte-ayurveda', 'Pflanzliche Extrakte / Ayurveda', 'Plant Extracts / Ayurveda', 'Traditionelle Heilpflanzen aus ayurvedischer Tradition. Coleus forskohlii, Ashwagandha, Bacopa, Kurkuma.'),
  ('gewichtsmanagement', 'Gewichtsmanagement / Stoffwechsel', 'Weight Management / Metabolism', 'Supplements zur Unterstützung bei Gewichtsabnahme und Stoffwechseloptimierung. Forskolin, Grüntee-Extrakt, L-Carnitin.'),
  ('kognition-nervensystem', 'Kognition / Nervensystem', 'Cognition / Nervous System', 'Supplements für Gehirn und geistige Leistungsfähigkeit. Omega-3-DHA, Bacopa, Ginkgo, Kakaoextrakt (kurzfristig).'),
  ('efsa-health-claims', 'EFSA-zugelassene Health Claims', 'EFSA-approved Health Claims', '⚠️ WICHTIG: Nur Supplements mit EFSA-zugelassenen Health Claims dürfen spezifische Gesundheitsaussagen tragen. Kakaoextrakt (Gefäßelastizität) ist zugelassen.'),
  ('pflanzliche-extrakte-beeren', 'Pflanzliche Extrakte / Beeren', 'Plant Extracts / Berries', 'Beerenextrakte mit bioaktiven Polyphenolen. Cranberry (PACs), Heidelbeere, Holunder.'),
  ('harnwege', 'Harnwegsgesundheit', 'Urinary Tract Health', 'Supplements zur Unterstützung der Harnwegsgesundheit und HWI-Prävention. Cranberry, D-Mannose.'),
