  ('erkaeltungsmittel', 'Erkältungsmittel (pflanzlich)', 'Herbal Cold Remedies', 'Pflanzen für Erkältungsbehandlung/-prävention. Echinacea, Holunder, Vitamin C, Zink.'),
  ('antivirale-pflanzen', 'Antivirale Pflanzen', 'Antiviral Herbs', 'Pflanzen mit antiviraler Wirkung (in vitro nachgewiesen). Holunder (Neuraminidase), Echinacea.'),
  ('asteraceae-kreuzallergie', '⛔ Asteraceae/Korbblütler-Kreuzallergie', '⛔ Asteraceae Cross-Allergy', '⛔ WARNUNG: Echinacea, Kamille, Arnika, Beifuß, Chrysanthemen, Löwenzahn. Bei Allergie gegen eines → alle meiden!'),
  ('autoimmun-kontraindiziert', '⛔ Bei Autoimmunerkrankungen kontraindiziert', '⛔ Contraindicated in Autoimmune', '⛔ Echinacea, Holunder, Astragalus, Beta-Glucane. Immunstimulation kann Schübe auslösen!'),
  ('well-established-use', '✅ Well-Established Use (EMA)', '✅ Well-Established Use (EMA)', '✅ Höchster EMA-Status für pflanzliche AM. Basierend auf klinischen Studien, nicht nur Tradition. NUR E. purpurea Presssaft!'),
  ('toxische-pflanzenteile', '⛔⛔ Toxische Pflanzenteile', '⛔⛔ Toxic Plant Parts', '⛔⛔ Holunder: Rohe Beeren, Blätter, Rinde, Stiele = GIFTIG (Sambunigrin → Blausäure)!'),
