  ('standardisierung-kritisch', '⛔ Standardisierung kritisch', '⛔ Standardization Critical', '⛔ Ginkgo: NUR EGb 761 oder Ph.Eur.-konform! 86% kommerzieller Produkte NICHT standardkonform! <5 ppm Ginkgolsäure!'),
  ('dopaminerge-pflanzen', '⭐ Dopaminerge Pflanzen', 'Dopaminergic Plants', 'Mucuna pruriens: Enthält L-DOPA (2-6%)! ⛔ PHARMAKOLOGISCH AKTIV wie Medikament! MAO-Hemmer-Kontraindikation!'),
  ('maennliche-fertilitaet', '⭐ Männliche Fertilität', 'Male Fertility', 'Mucuna: Bei INFERTILEN Männern: Testosteron +27-38%, Spermien bis +688%. Nicht bei Gesunden getestet!'),
  ('warfarin-kontraindikation', '⛔⛔ Warfarin ABSOLUT kontraindiziert', '⛔⛔ Warfarin ABSOLUTE contraindication', '⛔⛔ Lebensbedrohliche Blutungen bei gleichzeitiger Einnahme von Warfarin/Phenprocoumon dokumentiert!'),
  ('superfood-mythos', '⚠️ "Superfood" = Marketing, nicht Wissenschaft', '⚠️ "Superfood" = Marketing, not Science', '⚠️ EFSA hat ALLE Goji Health Claims abgelehnt. ORAC-Werte sind klinisch irrelevant (USDA zog Datenbank 2012 zurück).'),
  ('zeaxanthin-quelle', '✅ Beste natürliche Zeaxanthin-Quelle', '✅ Best Natural Zeaxanthin Source', '✅ 50-186 mg/100g = höchster bekannter natürlicher Zeaxanthin-Gehalt. 3 RCTs zu Makulapigment positiv.'),
  ('pestizid-risiko', '⚠️ Pestizidbelastung beachten', '⚠️ Pesticide Contamination Risk', '⚠️ RASFF-Meldungen: Carbofuran, Propargit. Bis 18 Pestizidrückstände/Probe. Bio-Qualität bevorzugen!'),
  ('ltp-allergie', '⛔ LTP-Allergie = Anaphylaxie-Risiko', '⛔ LTP Allergy = Anaphylaxis Risk', '⛔ Lyc e 3 (LTP) Hauptallergen. Kreuzreaktivität mit Tomate, Pfirsich, Nüsse. 2 Anaphylaxie-Fälle dokumentiert.'),
