  ('schwangerschaft-absolut-kontraindiziert', '⛔⛔ Schwangerschaft ABSOLUT kontraindiziert', '⛔⛔ Pregnancy ABSOLUTELY Contraindicated', '⛔⛔ Uterusstimulierend! Teratogenitäts-Hinweise! Traditionell als Abortivum!'),
  ('cyp-inhibitor-stark', '⛔ Starker CYP-Inhibitor', '⛔ Strong CYP Inhibitor', '⛔ CYP2D6: 9× Hemmung! CYP3A4: +40%! CYP2C9: 2×! Massive Interaktionen!'),
  ('kanzerogenitaet-risiko', '⚠️ Kanzerogenitäts-Risiko bei Langzeitanwendung', '⚠️ Carcinogenicity Risk with Long-term Use', '⚠️ NTP-Studie: Klare Evidenz bei Ratten. Max. 7-14 Tage Anwendung!'),
  ('artenschutz-cites', '🌿 CITES Appendix II geschützt', '🌿 CITES Appendix II Protected', '🌿 Gefährdete Art durch Übererntung! Kultivierte Quellen bevorzugen!'),
  ('extrakt-nicht-oel', '⚠️ Extrakt ≠ Öl - Verwechslungsgefahr!', '⚠️ Extract ≠ Oil - Confusion Risk!', '⚠️ Traubenkernextrakt (OPC 74-95%) ≠ Traubenkernöl (KEINE OPC)! Für OPC NUR Extrakt!'),
