  ('krebs-adjuvans', '⚠️⚠️ Krebs-Adjuvantien (NUR unter Arzt!)', 'Cancer Adjuvants', '⚠️⚠️ NUR ergänzend zur Standardtherapie! Lentinan = zugelassenes Arzneimittel Japan.'),
  ('skandal-zurueckgezogen', '⛔ SKANDAL: Studie zurückgezogen!', '⛔ SCANDAL: Study RETRACTED!', '⛔ Die Schlüsselstudie (Vinson 2012) wurde wegen DATENFÄLSCHUNG zurückgezogen! FTC-Strafe 3,5 Mio USD! Dr. Oz Senatsanhörung!'),
  ('koffein-risiko', '⚠️ Koffein-bedingte Risiken', '⚠️ Caffeine-Related Risks', '⚠️ Schlafstörungen, Tachykardie, Nervosität, Angst. Bei Sensibilität: entkoffeiniert wählen!'),
  ('hepatotoxizitaet', '⛔⛔ HEPATOTOXIZITÄT bei ≥800 mg EGCG!', '⛔⛔ HEPATOTOXICITY at ≥800 mg EGCG!', '⛔⛔ EFSA 2018: Statistisch signifikant erhöhte Transaminasen! Transplantationen! Todesfälle! KEINE sichere Obergrenze definierbar!'),
  ('nicht-nuechtern', '⛔ NIEMALS nüchtern einnehmen!', '⛔ NEVER take on empty stomach!', '⛔ Nüchterneinnahme = bis 5× höhere EGCG-Absorption → massiv erhöhtes Hepatotox-Risiko! EU-Pflicht-Warnhinweis!'),
  ('nadolol-kontraindikation', '⛔⛔ NADOLOL = Absolute Kontraindikation!', '⛔⛔ NADOLOL = Absolute Contraindication!', '⛔⛔ EGCG hemmt OATP1A2 → Nadolol-Absorption ↓85%! Therapieversagen! NIEMALS kombinieren!'),
  ('extrakt-nicht-tee', '⚠️ EXTRAKT ≠ Tee trinken!', '⚠️ EXTRACT ≠ Drinking Tea!', '⚠️ Extrakte haben anderes Sicherheitsprofil! Tee trinken = sicher (EFSA). Extrakt = Hepatotox-Risiko!'),
