  ('antidepressiva-pflanzlich', 'Pflanzliche Stimmungsaufheller', 'Herbal Antidepressants', 'Pflanzliche Supplements mit Evidenz bei Depression: Safran, Johanniskraut'),
  ('triterpen-saponine', 'Triterpen-Saponine (Dammarangerüst)', 'Triterpene Saponins (Dammarane)', '⭐ Ginsenoside sind glykosylierte Triterpen-Saponine mit Dammarangerüst. >200 verschiedene identifiziert. Zwei Haupttypen: PPD (Rb1, Rd, Rg3) = "beruhigend", PPT (Rg1, Re) = "stimulierend". Compound K = aktiver Darm-Metabolit.'),
  ('arecaceae', 'Palmen (Arecaceae)', 'Arecaceae (Palm Family)', 'Pflanzenfamilie mit Sägepalme (Serenoa repens)'),
  ('menopause', 'Wechseljahres-Supplements', 'Menopause Supplements', 'Phytotherapeutika für Wechseljahresbeschwerden: Salbei, Traubensilberkerze, Rotklee, Hopfen'),
  ('prostata', 'Prostata-Supplements', 'Prostate Supplements', 'Phytotherapeutika für BPH/LUTS: Sägepalme, Brennnesselwurzel, Kürbiskerne, Pygeum'),
  ('anthranoid-laxanzien', 'Anthranoid-Laxanzien (stimulierend)', 'Anthraquinone Laxatives (Stimulant)', 'Sennoside, Aloe, Rhabarber, Faulbaum, Cascara - Aktivierung durch Darmbakterien; Rhein-Anthron als aktiver Metabolit'),
  ('darmreinigung', 'Darmreinigungsmittel', 'Bowel Prep Agents', 'Produkte für Koloskopie-Vorbereitung (Macrogol, Senna-Früchte)'),
  ('gastroprotektiva', 'Gastroprotektiva', 'Gastroprotective Agents', 'DGL (ohne Glycyrrhizin) schützt Magenschleimhaut durch 15-PGDH-Hemmung → PGE2-Erhaltung. GutGard: 51% Symptomreduktion bei Dyspepsie.'),
  ('nervina', 'Nervina / Beruhigungsmittel', 'Nervines / Calmatives', 'S. lateriflora, Baldrian, Passionsblume, Hopfen - anxiolytisch/sedierend'),
  ('tcm-pflanzen', 'TCM-Heilpflanzen', 'TCM Medicinal Plants', 'S. baicalensis (Huang Qin), Astragalus, Ginseng - Traditionelle Chinesische Medizin'),
  ('pflanzliche-antidepressiva', 'Pflanzliche Antidepressiva', 'Herbal Antidepressants', 'Johanniskraut (Hypericum), Safran (Crocus sativus) - evidenzbasiert für Depression'),
  ('testosteron-marketing', '⚠️ ''Testosteron-Booster'' (MARKETING)', '⚠️ ''Testosterone Boosters'' (MARKETING)', '⚠️ Tribulus, Tongkat Ali, Maca - beworben als Testosteron-Booster, aber WISSENSCHAFTLICH NICHT BELEGT!'),
  ('cyp-induktoren', '⚠️ CYP450-Induktoren', '⚠️ CYP450 Inducers', '⚠️ Johanniskraut (stärkster pflanzlicher!), Ginkgo - KRITISCHE INTERAKTIONEN!'),
  ('mundgesundheit', 'Mundgesundheit', 'Oral Health', 'Supplements für Zähne, Zahnfleisch, Mundhygiene; Triphala-Mundspülung, CoQ10'),
  ('hydroxyzimtsaeuren', 'Hydroxyzimtsäuren (Phenylpropanoide)', 'Hydroxycinnamic Acids', 'Strukturklasse der Phenolsäuren mit C6-C3-Grundgerüst. Chlorogensäure (Ester), Kaffeesäure (Catechol, IARC 2B!), Ferulasäure (O-methyliert, NICHT IARC). Metabolische Vernetzung: CGA → Kaffeesäure → Ferulasäure.'),
  ('phenolsaeure-ester', 'Phenolsäure-Ester', 'Phenolic Acid Esters', 'Chlorogensäure = Ester aus Kaffeesäure + Chinasäure. Gamma-Oryzanol = Ester aus Ferulasäure + Sterolen. Ester müssen oft erst hydrolysiert werden für Bioverfügbarkeit.'),
  ('hydroxybenzoesaeuren', 'Hydroxybenzoesäuren', 'Hydroxybenzoic Acids', 'Phenolsäuren mit C6-C1-Grundgerüst. Gallussäure (3 OH = Pyrogallol-Typ), Protocatechusäure (2 OH = Catechol-Typ). Baustein von Tanninen.'),
  ('harnwegsgesundheit', 'Harnwegsgesundheit', 'Urinary Tract Health', 'Uva Ursi, Cranberry, D-Mannose, Goldrute, Orthosiphon - für Blasen-/Nierengesundheit'),
  ('traditionelle-arzneimittel', 'Traditionelle pflanzliche Arzneimittel (EU)', 'Traditional Herbal Medicinal Products', 'EU-registrierte traditionelle Arzneimittel gemäß Richtlinie 2004/24/EG; Uva Ursi, Baldrian, Johanniskraut, etc.'),
  ('zeitbeschraenkt', '⚠️ Zeitlich beschränkte Anwendung', '⚠️ Time-Limited Use', 'Supplements/Arzneimittel mit strenger Anwendungsdauer; Uva Ursi (max. 1 Woche), Helmkraut (max. 2 Wochen)'),
  ('schlaf-beruhigung', 'Schlaf & Beruhigung', 'Sleep & Relaxation', 'Baldrian, Hopfen, Melisse, Passionsblume, Lavendelöl, Melatonin - für Schlafstörungen und nervöse Unruhe'),
  ('fda-warnung', '⛔ FDA-Warnung', 'FDA Warning', 'Substanzen mit expliziter FDA-Warnung: Vinpocetin (Teratogenität 2019)'),
  ('huminstoffe', 'Huminstoffe (Humic Substances)', 'Humic Substances', 'Natürliche organische Substanzen aus Zersetzung pflanzlicher Materie. Drei Fraktionen: Humin (unlöslich), Huminsäure (löslich pH >2), Fulvosäure (löslich alle pH). Fulvosäure in EU als Novel Food NICHT zugelassen, Huminsäure nur in NEM erlaubt.'),
  ('chelatbildner', 'Chelatbildner / Chelating Agents', 'Chelating Agents', 'Substanzen, die Metallionen binden und deren Transport beeinflussen. Fulvo- und Huminsäure werden als natürliche Chelatbildner beworben, aber KEINE Humanstudien belegen Entgiftungswirkung.'),
  ('gruene-superfoods', 'Grüne Superfoods / Chlorophyll', 'Green Superfoods / Chlorophyll', 'Weizengras, Gerstengras, Spirulina, Chlorella - chlorophyllreiche Produkte ohne belegte Health Claims'),
